int naive(char *T, int n, char *P, int m) {
  for (int i = 0; i < n - m + 1; ++i) {
    bool found = true;
    for (int k = 0; k < m; ++k) {
      if (P[k] != T[i + k]) {
        found = false;
        break;
      }
    }
    if (found) return i;
  }
  return -1;
}

int kmp(char *T, int n, char *P, int m, int *F) {
  int j = 0;  // position in pattern
  for (int i = 0; i < n; ++i) {
    while (j > 0 && T[i] != P[j])
      j = F[j - 1];     // fall back using failure function
    if (T[i] == P[j])
      j++;
    if (j == m)
      return i - m + 1;  // match found at offset i-m+1
  }
  return -1;
}
// Time: O(n) -- each character of T examined at most twice

void computeF(char *P, int m, int *F) {
  F[0] = 0;
  int j = 0;
  for (int i = 1; i < m; ++i) {
    while (j > 0 && P[i] != P[j])
      j = F[j - 1];
    if (P[i] == P[j])
      j++;
    F[i] = j;
  }
}
// Time: O(m)
